import org.apache.commons.math.util.MathUtils;

public class TestNaNComparison {
    public static void main(String[] args) {
        // Test the fixed behavior
        System.out.println("Testing NaN comparison behavior:");

        // Array comparison with NaN - should return false with equals() (excluding NaN values)
        double[] arr1 = {Double.NaN, 1.0, Double.NaN};
        double[] arr2 = {Double.NaN, 1.0, Double.NaN};
        boolean resultEquals = MathUtils.equals(arr1, arr2);
        System.out.println("MathUtils.equals([NaN, 1.0, NaN], [NaN, 1.0, NaN]) = " + resultEquals);

        // Array comparison with NaN - should return true with equalsIncludingNaN() (including NaN values)
        boolean resultEqualsIncNaN = MathUtils.equalsIncludingNaN(arr1, arr2);
        System.out.println("MathUtils.equalsIncludingNaN([NaN, 1.0, NaN], [NaN, 1.0, NaN]) = " + resultEqualsIncNaN);

        // Scalar NaN comparison with equals - should return false
        boolean scalarEquals = MathUtils.equals(Double.NaN, Double.NaN);
        System.out.println("MathUtils.equals(NaN, NaN) = " + scalarEquals);

        // Scalar NaN comparison with equalsIncludingNaN - should return true
        boolean scalarEqualsIncNaN = MathUtils.equalsIncludingNaN(Double.NaN, Double.NaN);
        System.out.println("MathUtils.equalsIncludingNaN(NaN, NaN) = " + scalarEqualsIncNaN);

        // Test regular values still work
        double[] arr3 = {1.0, 2.0, 3.0};
        double[] arr4 = {1.0, 2.0, 3.0};
        boolean resultRegular = MathUtils.equals(arr3, arr4);
        System.out.println("MathUtils.equals([1.0, 2.0, 3.0], [1.0, 2.0, 3.0]) = " + resultRegular);
    }
}

